patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..ca8b2defbcc1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3150,6 +3150,24 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // select (select C1, C2, false), T, (select C1, F1, F2) -> select C1, (select C2, T, F1), F2
+  // This pattern restructures nested selects when the outer condition is a logical AND
+  // and the false value is a select with the same condition.
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    if (match(CondSI->getFalseValue(), m_Zero()) && CondSI->hasOneUse()) {
+      if (auto *FalseSI2 = dyn_cast<SelectInst>(FalseVal)) {
+        if (CondSI->getCondition() == FalseSI2->getCondition() && FalseSI2->hasOneUse()) {
+          return SelectInst::Create(CondSI->getCondition(),
+                                    Builder.CreateSelect(CondSI->getTrueValue(), TrueVal,
+                                                         FalseSI2->getTrueValue(),
+                                                         SI.getName() + ".inner"),
+                                    FalseSI2->getFalseValue(), SI.getName());
+        }
+      }
+    }
+  }
+
+
